const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let isValid = false;
  let pick_card = false;
  let numbercard = 3;
  let needs_image = false;
  let topic = "general";
  let reason = "Câu hỏi chưa rõ ràng hoặc không liên quan đến Tarot.";

  let rawText = "";
  if (data.choices && data.choices[0] && data.choices[0].message) {
    rawText = data.choices[0].message.content || "";
  } else {
    rawText = data.output || data.text || "";
  }

  if (typeof rawText === 'object') {
    rawText = JSON.stringify(rawText);
  }
  rawText = rawText.trim();

  if (rawText.includes('```')) {
    rawText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  }

  try {
    const parsed = JSON.parse(rawText);
    isValid = parsed.isValid;
    pick_card = parsed.pick_card;
    if (parsed.numbercard !== undefined) numbercard = parseInt(parsed.numbercard) || 3;
    if (parsed.needs_image !== undefined) needs_image = Boolean(parsed.needs_image);
    if (parsed.topic) topic = parsed.topic;
    reason = parsed.reason || "ok";
  } catch (e) {
    const lowerText = rawText.toLowerCase();
    if (lowerText.includes('"isvalid": true') || lowerText.includes('isvalid: true')) {
      isValid = true;
      if (lowerText.includes('"pick_card": true') || lowerText.includes('pick_card: true')) pick_card = true;
      if (lowerText.includes('"needs_image": true') || lowerText.includes('needs_image: true')) needs_image = true;

      if (lowerText.includes('"topic": "love"') || lowerText.includes('topic: "love"')) topic = "love";
      else if (lowerText.includes('"topic": "career"') || lowerText.includes('topic: "career"')) topic = "career";
      else if (lowerText.includes('"topic": "finances"') || lowerText.includes('topic: "finances"')) topic = "finances";

      const matchNum = rawText.match(/"numbercard"\s*:\s*(\d+)/i) || rawText.match(/numbercard\s*:\s*(\d+)/i);
      if (matchNum && matchNum[1]) numbercard = parseInt(matchNum[1]) || 3;
      reason = "ok";
    } else {
      isValid = false;
      const match = rawText.match(/"reason"\s*:\s*"([^"]+)"/i);
      if (match && match[1]) reason = match[1];
    }
  }

  if (typeof isValid === 'string') isValid = (isValid.toLowerCase() === 'true');
  else isValid = Boolean(isValid);

  if (typeof pick_card === 'string') pick_card = (pick_card.toLowerCase() === 'true');
  else pick_card = Boolean(pick_card);

  if (isValid && pick_card) {
    reason = "ok";
  } else if (!isValid && (!reason || reason === "ok" || reason === "undefined")) {
    reason = "Câu hỏi không phù hợp. Vui lòng đặt câu hỏi liên quan đến chủ đề Tarot.";
  }

  results.push({
    json: {
      output: {
        isValid: isValid,
        pick_card: pick_card,
        numbercard: numbercard,
        needs_image: needs_image,
        topic: topic,
        reason: reason,
        usage: data.usage || null,
        model: data.model || null
      }
    }
  });
}

return results;

for (const item of $input.all()) {
  const userMsg = $('Check câu hỏi').first().json.body.question || $('Check câu hỏi').first().json.body.message || "";
  const userProfile = $('Check câu hỏi').first().json.body.userProfile || { name: 'lữ khách', gender: 'bạn', user_persona: '' };
  const userName = userProfile.name;
  const userGender = userProfile.gender;
  const recentEvents = userProfile.user_persona;
  const readerPrompt = $('Check câu hỏi').first().json.body.reader_prompt || '';

  // Xây dựng lịch sử hội thoại dạng cặp đôi, ĐÁNH DẤU TURN
  const history = $('Check câu hỏi').first().json.body.history || [];
  let historyText = 'Chưa có lịch sử. Đây là tin nhắn đầu tiên.';
  if (history.length > 0) {
    let turnCount = 1;
    let historyLines = [];

    for (let i = 0; i < history.length; i++) {
        const msg = history[i];
        if (msg.role === 'user') {
            historyLines.push(`[Turn ${turnCount}] - Khách hàng: "${msg.content}"`);
        } else {
            let content = msg.content || '';
            if (content.length > 500) content = '...' + content.substring(content.length - 500);
            historyLines.push(`[Turn ${turnCount}] - Tarot Reader: "${content}"`);
            turnCount++; 
        }
    }
    historyText = historyLines.join('\n');
  }

  // Chèn Chân dung năng lượng
  let personaSection = '';
  if (recentEvents && recentEvents.trim() !== '') {
    personaSection = `\n\n### [HỒ SƠ VÀ BỐI CẢNH KHÁCH HÀNG]\n${recentEvents}`;
  }

  // Chèn thông tin các lá bài đã bốc trong phiên (nếu có) để trả lời follow-up
  const cards = $('Check câu hỏi').first().json.body.cards || [];
  let needs_image = false;
  let topic = 'general';
  try { 
    needs_image = $('Code in JavaScript').first().json.output.needs_image === true;
    topic = $('Code in JavaScript').first().json.output.topic || 'general';
  } catch(e) { console.log(e); }
  let cardsSection = '';
  if (cards && cards.length > 0) {
    cardsSection = `\n\n### [LÁ BÀI GẦN NHẤT ĐÃ BỐC]\n` + 
      cards.map((c, idx) => {
        let info = `- Lá ${idx + 1}: ${c.name} (${c.orientation || (c.isReversed ? 'Ngược' : 'Xuôi')})`;
        if (c.meaning) info += `: ${c.meaning}`;
        if (c.keyword && c.keyword[topic]) info += ` (Từ khóa ${topic}: ${c.keyword[topic]})`;
        else if (c.keyword && c.keyword.general) info += ` (Từ khóa chung: ${c.keyword.general})`;
        if (needs_image && c.description) info += ` (Hình ảnh: ${c.description})`;
        return info;
      }).join('\n') +
      `\n(Lưu ý: Khách có thể hỏi xoay vòng về ý nghĩa, hình ảnh của các lá bài trên ở bất kỳ turn nào)`;
  }

  const defaultSystemPrompt = `## ROLE: Master Tarot Reader thấu cảm và sâu sắc\n## TASK: Khách hàng đang trò chuyện hoặc hỏi thêm. Hãy trả lời sâu sắc, giữ đúng vai Tarot Reader.`;
  const narrativeBase = readerPrompt || defaultSystemPrompt;
  const systemPrompt = narrativeBase + `\n\n## USER INFO: Tên: ${userName}, Giới tính: ${userGender}. Hãy gọi tên và chủ động xưng hô một cách linh hoạt, tự nhiên như một người bạn tâm giao (không bị phụ thuộc máy móc vào giới tính, tùy theo phong cách của bạn).` + personaSection + cardsSection + `\n\n## QUY TẮC:\n1. Lời khuyên cần thực tế, hướng thiện và tích cực.\n2. Nếu có lịch sử, hãy tham chiếu để hiểu bối cảnh, nhưng TẬP TRUNG vào tin nhắn mới nhất.\n3. KHÔNG nhắc đến AI hay thuật toán.\n4. CHỦ ĐỘNG ĐÀO SÂU: Nếu khách hàng hỏi một câu về Tarot nhưng quá chung chung, ngắn gọn (ví dụ: "xem tình duyên", "công việc thế nào"), TUYỆT ĐỐI KHÔNG tự ý bịa ra trải bài. Hãy chủ động đặt 1-2 câu hỏi gợi mở, tinh tế để họ chia sẻ thêm bối cảnh hiện tại của họ trước khi tiến hành trải bài.\n5. KHÔNG HALLUCINATE HÌNH ẢNH: TUYỆT ĐỐI KHÔNG tự bịa ra chi tiết hình ảnh minh họa của lá bài. CHỈ miêu tả hình ảnh nếu có dữ liệu (Hình ảnh: ...) được cung cấp trong [LÁ BÀI GẦN NHẤT ĐÃ BỐC]. Nếu client không truyền dữ liệu hình ảnh, hãy giải nghĩa dựa trên tính biểu tượng chung và tuyệt đối KHÔNG tự vẽ ra các chi tiết thị giác (người, vật, cảnh) không có trong prompt.`;

  const userPrompt = `### 🗣️ TIN NHẮN MỚI NHẤT CỦA KHÁCH HÀNG:\n"${userMsg}"\n\n---\n\n### 📜 LỊCH SỬ HỘI THOẠI TRƯỚC ĐÓ (Sắp xếp từ cũ đến mới):\n${historyText}\n\n---\n\n-> Dựa vào bối cảnh trên, hãy trả lời tin nhắn mới nhất của khách hàng.`;

  item.json.conversationalPayload = {
    model: 'n8n2',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.8
  };
}

return $input.all();

