for (const item of $input.all()) {
  const question = ($('Check câu hỏi').first().json.body.question || '').trim();
  const q = question.toLowerCase();

  // ==============================================
  // Từ khóa tự tử / tự làm hại bản thân (phản hồi đặc biệt, nhân văn)
  // ==============================================
  const selfHarmKeywords = [
    'tự tử', 'tự sát', 'muốn chết', 'muốn tự tử', 'chán sống',
    'không muốn sống', 'mệt sống', 'cắt tay', 'nhảy cầu', 'treo cổ',
    'uống thuốc ngủ', 'uống thuốc chết', 'kết thúc cuộc đời',
    'toi mun chet', 'minh mun chet', 'tu tu', 'tu sat'
  ];

  // ==============================================
  // Từ khóa chửi thề, bạo lực, nội dung không phù hợp
  // ==============================================
  const blockedKeywords = [
    // Chửi thề tiếng Việt
    'địt', 'đụ', 'lồn', 'cặc', 'buồi', 'đmm', 'đkm', 'đm ',
    'vãi lồn', 'vãi cặc', 'con cặc', 'đồ chó', 'chó chết', 'thằng chó',
    'đéo mày', 'đết mày', 'đồ đần', 'thằng ngốc', 'con điếm',
    'chửi bữa', 'vãi đái', 'đéo hiểu', 'đéo biết', 'đéo cần',
    // Chửi thề không dấu (teen style)
    'dit', 'cac', 'lon', 'buoi', 'dcm', 'dmm', 'dkm', 'vl ',
    // Bạo lực
    'tao giết', 'tôi giết', 'mày chết đi', 'tao chém', 'chém chết',
    'đánh chết', 'giết người', 'đánh bom', 'tấn công',
    // Nội dung người lớn
    'khiêu dâm', 'phim sex', 'làm tình', 'quan hệ tình dục', 'xxx'
  ];

  let isBlocked = false;
  let blockedReason = '';

  // Kiểm tra tự tử trước (ưu tiên phản hồi nhân văn)
  for (const kw of selfHarmKeywords) {
    if (q.includes(kw)) {
      isBlocked = true;
      blockedReason = 'Mình nhận ra bạn đang trải qua giai đoạn rất khó khăn 💙 Tarot không thể hỗ trợ vấn đề này, nhưng bạn không cô đơn. Hãy gọi **đường dây hỗ trợ tâm lý miễn phí: 1800 599 920** (24/7) để được lắng nghe nhé. Khi bạn cảm thấy sẵn sàng hơn, mình luôn ở đây đồng hành cùng bạn.';
      break;
    }
  }

  // Kiểm tra chửi thề / bạo lực
  if (!isBlocked) {
    for (const kw of blockedKeywords) {
      if (q.includes(kw)) {
        isBlocked = true;
        blockedReason = 'Nội dung này không phù hợp với không gian Tarot. Bạn có muốn thử đặt câu hỏi khác về Tình cảm, Sự nghiệp, Tiền bạc hoặc Hành trình nội tâm không? Mình luôn sẵn sàng lắng nghe bạn 🌟';
        break;
      }
    }
  }

  item.json.isBlocked = isBlocked;
  item.json.blockedReason = blockedReason;
}

return $input.all();
